   "source": [
    "corr = df.drop(columns='target').corrwith(df['target']).abs().sort_values(ascending=False)\n",
    "print(corr.head())\n",
    "print(f\"\\nStrongest correlation: {corr.idxmax()} ({corr.max():.3f})\")"
   ]
