    "\n",
    "means = df.groupby(pd.qcut(df['bmi'], 4, labels=['Q1','Q2','Q3','Q4']))['target'].mean().round(1)\n",
    "print(means)\n",
    "print(f\"\\nYes — mean progression rises monotonically from Q1 to Q4 (r={r:.3f}, p={p:.2e}).\")"
